CREATE VIEW `ads_bi_pushclick_special_user_group_view` (`dt` COMMENT "事件日期", `id` COMMENT "id", `product_id` COMMENT "产品id", `event_tm` COMMENT "事件时间", `user_id` COMMENT "用户id", `send_id` COMMENT "send_id存放活动信息", `push_id` COMMENT "推送id", `project_id` COMMENT "项目id 5：阅读 8：短剧", `resource_type` COMMENT "推送类型", `server_push_tm` COMMENT "推送时间") AS SELECT `ods_log`.`ods_sensors_production_pushclick`.`dt`, `ods_log`.`ods_sensors_production_pushclick`.`id`, `ods_log`.`ods_sensors_production_pushclick`.`app_product_id` AS `product_id`, `ods_log`.`ods_sensors_production_pushclick`.`event_tm`, `ods_log`.`ods_sensors_production_pushclick`.`identity_user_id` AS `user_id`, `ods_log`.`ods_sensors_production_pushclick`.`send_id`, `ods_log`.`ods_sensors_production_pushclick`.`push_id`, `ods_log`.`ods_sensors_production_pushclick`.`project_id`, split_part(`ods_log`.`ods_sensors_production_pushclick`.`send_id`, '_', 2) AS `resource_type`, date_format(str_to_date(right(`ods_log`.`ods_sensors_production_pushclick`.`send_id`, 8), '%Y%m%d'), '%Y-%m-%d') AS `server_push_tm`
FROM `ods_log`.`ods_sensors_production_pushclick`
WHERE ((((`ods_log`.`ods_sensors_production_pushclick`.`send_id` IS NOT NULL) AND (`ods_log`.`ods_sensors_production_pushclick`.`send_id` != '')) AND (`ods_log`.`ods_sensors_production_pushclick`.`send_id` != 'null')) AND (`ods_log`.`ods_sensors_production_pushclick`.`send_id` != ')')) AND ((split_part(`ods_log`.`ods_sensors_production_pushclick`.`send_id`, '_', 2)) = 'push');